    [self POST:@"order/refresh" params:params callback:callback];
}

- (void)getRecentOrdersFromOtherUsersWithCount:(NSUInteger)count callback:(WBOtherUserOrderListCallback)callback {
    NSUInteger maxCount = 50;
    if (count > maxCount) count = maxCount;
    NSDictionary *params = @{
        @"size" : @(count),
    };
    [self POST:@"order/recent" params:params callback:^(id  _Nullable json, NSError * _Nullable error) {
        NSParameterAssert(json == nil ^ error == nil);
        if (error) return callback(nil, error);
        NSArray<WBOtherUserOrderModel *> *orders = [NSArray modelArrayWithClass:[WBOtherUserOrderModel class] json:json];
        return callback(orders, nil);
    }];
}

- (void)reserveVappWithVappId:(NSInteger)vAppId callback:(WBNetworkBaseCallback)callback {
    NSDictionary *params = @{
        @"id" : @(vAppId),
    };
    [self POST:@"aapp/reserve" params:params callback:callback];
}

